-- microgrid.micro_grid_key_scenes definition

-- Drop table

-- DROP TABLE microgrid.micro_grid_key_scenes;

CREATE TABLE microgrid.micro_grid_key_scenes (
	starttime timestamp NULL, -- 更新时间
	curr_flag bool NULL, -- 是否有效
	id int4 NULL, -- 唯一标识ID
	scenes_name varchar NULL, -- 场景名称
	key_scenes_old varchar NULL, -- 重要场景全称（旧）
	key_scenes_new varchar NULL, -- 重要场景全称（新）
	city varchar NULL, -- 城市
	first_scene_label varchar NULL, -- 一级标签
	second_scene_label varchar NULL, -- 二级标签
	third_scene_label varchar NULL, -- 三级标签
	the_geom geometry NULL, -- 边框信息
	wgid varchar NULL, -- 归属微网格
	CONSTRAINT enforce_dims_the_geom CHECK ((st_ndims(the_geom) = 2)),
	CONSTRAINT enforce_geotype_the_geom CHECK (((geometrytype(the_geom) = 'POLYGON'::text) OR (the_geom IS NULL))),
	CONSTRAINT enforce_srid_the_geom CHECK ((st_srid(the_geom) = 4326))
);
CREATE INDEX micro_grid_key_scenes_gist ON microgrid.micro_grid_key_scenes USING gist (the_geom);
COMMENT ON TABLE microgrid.micro_grid_key_scenes IS '督办重要场景表';

