COMMENT ON COLUMN microgrid.micro_grid_key_scenes.scenes_name IS '场景名称';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.key_scenes_old IS '重要场景全称（旧）';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.key_scenes_new IS '重要场景全称（新）';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.city IS '城市';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.first_scene_label IS '一级标签';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.second_scene_label IS '二级标签';
COMMENT ON COLUMN microgrid.micro_grid_key_scenes.third_scene_label IS '三级标签';
